}

header {
  margin-top: 3em;
  margin-bottom: 3em;
  font-size: 0.8em;
}

header h1 {
  font-family: var(--font-sans);
  color: var(--color-main);
  text-wrap: balance;
  max-width: 90%;
  margin-bottom: 0;
  font-size: 2em;
  font-weight: 800;
  line-height: 1.2;
}

header p {
  font-size: 1em;
}

header li {
  font-size: 1em;
}

header section h2 {
  font-size: 1em;
}

header section {
  margin-bottom: 1em;
}

header .authors-and-affiliation .formattedAuthors {
  text-transform: capitalize;
  margin-bottom: 1em;
  font-size: 1.35em;
  line-height: 1.2;
}

header .authors-and-affiliation .formattedAuthors sup {
  color: var(--color-main-light-text);
  vertical-align: super;
  margin-left: 0.15ch;
  font-weight: 400;
}

header .formattedAffiliations {
  margin: 0;
  padding: 0;
  font-size: 0.95em;
}

header .formattedAffiliations li {
  margin: 0;
  padding: 0;
  list-style-type: none;
}

header .formattedAffiliations li small {
  color: var(--color-main-light-text);
  font-size: 1.1em;
  line-height: 1;
}

header .formattedAffiliations li .affiliation-decoration {
  display: none;
}

header .formattedAffiliations li .affiliationlabel {
  color: var(--color-main-light-text);
  font-weight: 600;
  line-height: 1;
  display: none;
}

header .separator {
  display: none;
}

header .correspondingList {
  margin-top: 1em;
  font-size: 0.9em;
}

header .correspondingList p {
  margin-right: 3ch;
  display: inline;
}

header .correspondingList h2 {
  margin-right: 3ch;
  display: inline;
}

header .doi-licence {
  border-top: 1px solid var(--color-main-light);
  border-bottom: 1px solid var(--color-main-light);
  color: var(--color-main);
  justify-content: space-between;
  gap: 1ch;
  margin-top: 1em;
  font-size: 0.8em;
  display: flex;
}

header .doi-licence .forcitation {
  position: runngin(citation);
  align-items: center;
  gap: 2ch;
  margin-right: auto;
  display: none;
}

header .doi-licence .dates {
  gap: 2ch;
  margin-right: auto;
  display: flex;
}

header .doi-licence .dates time {
  font-weight: 600;
}

header .doi-licence .logos {
  justify-content: end;
  align-items: center;
  gap: 3ch;
  display: flex;
}

header .doi-licence .doi:before {
  background: url('/images/doi_logo.svg') 0 0 / cover;
  width: 30px;
  height: 30px;
  display: inline-block;
}

