  background: var(--color-light-back);
  gap: 5ch;
  margin-bottom: 3em;
  padding: 0 3ch 1em;
  font-size: 0.8em;
}

#abstract-wrapper p {
  text-align: left;
  margin: 0;
}

#abstract-wrapper h2 {
  border-bottom: 2px solid var(--color-main);
  column-span: all;
  text-transform: uppercase;
  color: var(--color-main);
  margin-bottom: 1em;
  font-size: 1em;
  font-weight: 600;
  display: block;
}

#abstract-wrapper img {
  width: 100%;
  height: auto;
  margin: 2em 0;
}

#abstract-wrapper img.landscape {
  max-width: 100%;
  height: auto;
}

#abstract-wrapper img.portrait {
  max-width: 100%;
  height: auto;
}

#abstract-wrapper .keywords {
  column-span: all;
  margin-top: 1em;
}

#abstract-wrapper .keywords .title {
  color: var(--color-main);
  font-weight: 600;
}

article {
  margin: 0 var(--offset-margin);
}

article h2 {
  border-bottom: 1px solid var(--color-main);
  font-weight: 600;
}

article p {
  text-align: justify;
  -webkit-hyphens: auto;
  hyphens: auto;
  margin-top: 0;
  margin-bottom: 1em;
  font-size: 0.9em;
  line-height: 1.5;
}

article li {
  text-align: justify;
  -webkit-hyphens: auto;
  hyphens: auto;
  margin-top: 0;
  margin-bottom: 1em;
  font-size: 0.9em;
  line-height: 1.5;
}

sub,
sup {
  line-height: 0;
}

.article :-webkit-any(h1, h2, h3, h4, h5) {
  color: var(--color-main);
  border-color: var(--color-main-light-text);
  font-weight: 400;
  line-height: 1.25;
}

.article :is(h1, h2, h3, h4, h5) {
  color: var(--color-main);
  border-color: var(--color-main-light-text);
  font-weight: 400;
  line-height: 1.25;
}

.article h2 {
  font-size: 1.375em;
}

.article h3 {
  font-size: 1.2em;
}

.article h4 {
  color: var(--color-main);
  font-size: 1.05em;
}

.article h5 {
  color: var(--color-main);
  font-size: 1em;
  font-weight: 400;
}

.article {
  counter-reset: figure;
}

.article figure {
  break-inside: avoid;
  counter-increment: figure;
  margin: 0 auto auto;
}

.article figure img {
  object-fit: contain;
  border: 1px solid var(--color-main-light-text);
  width: 100%;
  margin: auto;
  padding: 1em 5ch;
}

.article figure figcaption {
  max-width: 80ch;
  margin: 0 auto 0.8em;
  font-size: 0.8em;
}

.article figure figcaption:before {
  content: 'Fig.\00A0'counter(figure);
  color: var(--color-main-light-text);
  margin-right: 1ch;
  font-weight: 600;
}

table {
  border-collapse: collapse;
  border: 1px solid var(--color-main-light-text);
  width: 100%;
  font-size: 0.9em;
}

table td {
  border: 1px solid var(--color-main-light-text);
  padding: 0.3em 1ch;
}

table td p {
  margin: 0;
}

table thead {
  background: var(--color-main-lighter);
}

#cloneCite {
  position: running(citation);
  font-size: 0.8em;
}

#cloneCite .journalname {
  font-weight: 600;
}

#cloneCite .citation {
  font-weight: 500;
}

#cloneCite .citation:before {
  content: '|';
  color: var(--color-main-light);
  margin: 0 2ch;
  font-weight: 800;
}

.licence {
  position: running(licence);
}

.qrcode {
  position: running(qrcode);
  width: 100px;
}

.journal-name {
  string-set: journal content(text);
}

@page {
  size: letter;
  margin: 15mm 15mm 22mm 18mm;

  @top-right {
    content: element(citation);
    text-align: right;
    border-bottom: 1px solid var(--color-main);
    color: var(--color-main);
    display: block;
    letter-spacing: 0.05ch;
    font-weight: 500;
    height: 40px;
    font-size: 0.8em;
    align-item: end;
    padding-top: 1.4em;
  }

  @bottom-left {
    color: var(--color-main);
    font-size: 0.8em;
  }

  @bottom-right {
    content: counter(page) '/' counter(pages);
  }

  @bottom-left {
    content: element(licence);
    font-size: 0.8em;
  }
}

@page :first {
  margin-bottom: 8em;

  @bottom-center {
    content: element(licence);
    font-size: 0.8em;
  }

  @bottom-left {
    content: element(qrcode);
    width: 100px;
    top: 0;
  }

  @bottom-right {
    content: counter(page) '/' counter(pages);
  }

  @top-right {
    content: none;
    border-bottom: 0;
  }

  @top-left {
    content: none;
  }
}

.toc-wrapper {
  display: none;
}

h1,
h2,
h3,
h4,
h5,
h6 {
  break-after: avoid;
  margin-top: 1.8em;
  margin-bottom: 0.6em;
}

h1 + h2 {
  margin-top: 0.2em;
}

h2 + h3,
h3 + h4 {
  margin-top: 0.6em;
}
